using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ───────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var model = Environment.GetEnvironmentVariable("OPENAI_CHAT_MODEL") ?? "gpt-4o-mini";

// ── Build chat client with automatic tool invocation ────────────────────────
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── Register tools ──────────────────────────────────────────────────────────
var notepad = new Notepad();
var searcher = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(searcher.SearchWeb),
    AIFunctionFactory.Create(searcher.ReadWebPage),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// ── Get research topic ──────────────────────────────────────────────────────
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍  Researching: {topic}\n");

// ── Run the agent ───────────────────────────────────────────────────────────
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic you must:
        1. Search the web with several varied queries to cover different angles.
        2. Read the most promising pages to gather detailed information.
        3. Take organized notes on key findings (group by subtopic).
        4. After consulting at least 3 sources, review your notes and compile
           a well-structured, comprehensive summary with source citations.

        Always save notes before writing the final summary.
        """),
    new(ChatRole.User, $"Research this topic and provide a detailed summary: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

var response = await client.GetResponseAsync(messages, options);

Console.WriteLine("\n========== RESEARCH SUMMARY ==========\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n=======================================");

// Show collected notes
var allNotes = notepad.GetAllNotes();
if (allNotes.Count > 0)
{
    Console.WriteLine($"\n📝  {allNotes.Count} note(s) collected during research:\n");
    foreach (var (noteTopic, content) in allNotes)
        Console.WriteLine($"  [{noteTopic}] {content}");
}

