/// <summary>Provides web search and page-reading capabilities.</summary>
sealed class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for a query. Returns titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔎  Searching: \"{query}\"");
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);
            var results = ParseSearchResults(html);

            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            var count = Math.Min(results.Count, 8);
            for (var i = 0; i < count; i++)
            {
                var r = results[i];
                sb.AppendLine($"{i + 1}. {r.Title}");
                sb.AppendLine($"   URL: {r.Url}");
                sb.AppendLine($"   {r.Snippet}");
                sb.AppendLine();
            }

            Console.WriteLine($"       ✅ Found {count} results");
            return sb.ToString();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"       ❌ Search failed: {ex.Message}");
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and read the text content of a web page at the given URL.")]
    public async Task<string> ReadWebPage(
        [Description("The full URL of the web page to read")] string url)
    {
        Console.WriteLine($"  📄  Reading: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = ExtractText(html);

            const int maxLen = 8_000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n\n[Content truncated]";

            Console.WriteLine($"       ✅ Read {text.Length:#,0} chars");
            return text;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"       ❌ Failed: {ex.Message}");
            return $"Failed to read page: {ex.Message}";
        }
    }

    // ── HTML parsing helpers ────────────────────────────────────────────────

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();

        var links = Regex.Matches(html,
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);
        var snippets = Regex.Matches(html,
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        for (var i = 0; i < links.Count; i++)
        {
            var rawUrl = links[i].Groups[1].Value;
            var actualUrl = ExtractRedirectUrl(rawUrl);
            var title = StripTags(links[i].Groups[2].Value).Trim();
            var snippet = i < snippets.Count
                ? StripTags(snippets[i].Groups[1].Value).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(actualUrl))
                results.Add(new(title, actualUrl, snippet));
        }

        return results;
    }

    private static string ExtractRedirectUrl(string ddgUrl)
    {
        var m = Regex.Match(ddgUrl, @"uddg=([^&]+)");
        return m.Success ? Uri.UnescapeDataString(m.Groups[1].Value) : ddgUrl;
    }

    private static string ExtractText(string html)
    {
        // Strip script / style blocks, then tags, decode entities, collapse whitespace
        html = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        html = StripTags(html);
        html = WebUtility.HtmlDecode(html);
        html = Regex.Replace(html, @"[ \t]+", " ");
        html = Regex.Replace(html, @"(\s*\n\s*)+", "\n");
        return html.Trim();
    }

    private static string StripTags(string html) => Regex.Replace(html, @"<[^>]+>", " ");

    private record SearchResult(string Title, string Url, string Snippet);
}

/// <summary>In-memory note-taking tool for organizing research findings.</summary>
sealed class Notepad
{
    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Save a research note under a subtopic. Use this to record key findings from sources.")]
    public string AddNote(
        [Description("The subtopic or category")] string topic,
        [Description("The note content")] string content)
    {
        _notes.Add((topic, content));
        Console.WriteLine($"  📝  Note [{topic}]: {Truncate(content, 80)}");
        return $"Note saved under '{topic}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes grouped by topic.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        foreach (var group in _notes.GroupBy(n => n.Topic))
        {
            sb.AppendLine($"## {group.Key}");
            foreach (var (_, content) in group)
                sb.AppendLine($"  - {content}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public List<(string Topic, string Content)> GetAllNotes() => [.. _notes];

    private static string Truncate(string s, int max) =>
        s.Length <= max ? s : s[..(max - 3)] + "...";
}

