            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);
        var snippets = Regex.Matches(html,
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        for (var i = 0; i < links.Count; i++)
        {
            var rawUrl = links[i].Groups[1].Value;
