+/// <summary>In-memory note-taking tool for organizing research findings.</summary>
+sealed class Notepad
+{
+    private readonly List<(string Topic, string Content)> _notes = [];
+
+    [Description("Save a research note under a subtopic. Use this to record key findings from sources.")]
+    public string AddNote(
+        [Description("The subtopic or category")] string topic,
+        [Description("The note content")] string content)
+    {
+        _notes.Add((topic, content));
+        Console.WriteLine($"  📝  Note [{topic}]: {Truncate(content, 80)}");
+        return $"Note saved under '{topic}'. Total notes: {_notes.Count}.";
+    }
+
+    [Description("Retrieve all saved research notes grouped by topic.")]
+    public string GetNotes()
+    {
+        if (_notes.Count == 0)
+            return "No notes saved yet.";
+
+        var sb = new StringBuilder();
+        foreach (var group in _notes.GroupBy(n => n.Topic))
+        {
+            sb.AppendLine($"## {group.Key}");
+            foreach (var (_, content) in group)
+                sb.AppendLine($"  - {content}");
+            sb.AppendLine();
+        }
+
+        return sb.ToString();
+    }
+
+    public List<(string Topic, string Content)> GetAllNotes() => [.. _notes];
+
+    private static string Truncate(string s, int max) =>
+        s.Length <= max ? s : s[..(max - 3)] + "...";
+}
